interface User { id: string; name: string; avatar: string; }

// Before: O(n) on every lookup
function getUserSlow(users: User[], id: string): User | undefined {
  return users.find(u => u.id === id);
}

// After: build once O(n), then O(1) per lookup
function buildUserMap(users: User[]): Map<string, User> {
  return new Map(users.map(u => [u.id, u]));
}

const userMap = buildUserMap(apiResponse.users);
const user = userMap.get(id); // O(1)

